def pyramidTransition(bottom, allowed):
    from collections import defaultdict
    m = defaultdict(list)
    for a in allowed: m[a[:2]].append(a[2])
    def dfs(last_row, next_row):
        if len(last_row) == 1: return True
        if len(next_row) + 1 == len(last_row):
            return dfs(next_row, "")
        idx = len(next_row)
        for c in m[last_row[idx:idx+2]]:
            if dfs(last_row, next_row + c): return True
        return False
    return dfs(bottom, "")

